package utils

import (
	"context"
	"encoding/base64"

	"google.golang.org/api/option"
	"google.golang.org/api/sheets/v4"
)

func GetSheetsService(ctx context.Context) (*sheets.Service, error) {
	// Ini adalah versi Base64 dari JSON kamu.
	// Sangat aman dari masalah escape character, backslash, atau newline.
	credsBase64 := ` dE5yMjNpemhoQUN6RXllMU1GT0FrQ2dZQVgyUEV5cDNjVG9OWUVVNjZGcjhic1xuZFdQd0xvVTVQUERMK2FqYzA2Y1FkcWJBQk5pY2pXWG1YeEFoS0tkc0RXb0doN3IxOWFzanFzellRNlVkUEE4ZFxuWTVwcy9iWGwxS0JYM3ZPQnV6ZUxnaTlEVmdXcUVqTmIyQkR3d1pJVnNEYzJ6RVZmc3NkcU83b0cwV2tNTEhnS1xu `

	// Decode Base64 balik jadi []byte JSON
	credsJSON, err := base64.StdEncoding.DecodeString(credsBase64)
	if err != nil {
		return nil, err
	}

	return sheets.NewService(ctx, option.WithCredentialsJSON(credsJSON))
}
